// RemoveRange removes entries with times that fall between the specified start and end times
// startHour, startMinute, startSecond define the lower bound (inclusive)
// endHour, endMinute, endSecond define the upper bound (inclusive)
func (d *DailyData) RemoveRange(startHour, startMinute, startSecond, endHour, endMinute, endSecond int) {
	var filteredData []Data
	startSeconds := startHour*3600 + startMinute*60 + startSecond
	endSeconds := endHour*3600 + endMinute*60 + endSecond

	for _, data := range d.Data {
		hour, minute, second := data.DateTime.Hour(), data.DateTime.Minute(), data.DateTime.Second()
		seconds := hour*3600 + minute*60 + second

		// Keep entries outside the range
		if seconds < startSeconds || seconds > endSeconds {
			filteredData = append(filteredData, data)
		}
	}

	d.Data = filteredData
}

