// RemoveAtDateTime removes a single entry at the specific hour, minute, second
func (d *DailyData) RemoveAtDateTime(hour, minute, second int) {
	var filteredData []Data
	targetSeconds := hour*3600 + minute*60 + second

	for _, data := range d.Data {
		dataHour, dataMinute, dataSecond := data.DateTime.Hour(), data.DateTime.Minute(), data.DateTime.Second()
		dataSeconds := dataHour*3600 + dataMinute*60 + dataSecond

		// Keep all entries except the exact match
		if dataSeconds != targetSeconds {
			filteredData = append(filteredData, data)
		}
	}

	d.Data = filteredData
